import{c as a,Q as s,j as e,m as d}from"./chunks/framework.Bhbi9jCp.js";const b=JSON.parse('{"title":"采样率、帧率、码率、分辨率","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/03-采样率、帧率、码率、分辨率.md","filePath":"mediaTechLearning/03-采样率、帧率、码率、分辨率.md","lastUpdated":1780887690000}'),i={name:"mediaTechLearning/03-采样率、帧率、码率、分辨率.md"};function r(p,t,n,h,l,o){return s(),e("div",null,[...t[0]||(t[0]=[d(`<h1 id="采样率、帧率、码率、分辨率" tabindex="-1">采样率、帧率、码率、分辨率 <a class="header-anchor" href="#采样率、帧率、码率、分辨率" aria-label="Permalink to &quot;采样率、帧率、码率、分辨率&quot;">​</a></h1><p>音视频参数看起来多,其实都在回答一个问题:<strong>每秒要处理多少数据</strong>。</p><blockquote><p>一句话先记住:<strong>分辨率和帧率决定原始数据量,码率决定压缩后每秒给多少预算,采样率决定音频时间精度</strong>。清晰度、流畅度、延迟、成本都从这几个数长出来。</p></blockquote><hr><h2 id="一、分辨率-一帧有多少像素" tabindex="-1">一、分辨率:一帧有多少像素 <a class="header-anchor" href="#一、分辨率-一帧有多少像素" aria-label="Permalink to &quot;一、分辨率:一帧有多少像素&quot;">​</a></h2><p>常见分辨率:</p><table tabindex="0"><thead><tr><th>名称</th><th>尺寸</th></tr></thead><tbody><tr><td>720p</td><td>1280 x 720</td></tr><tr><td>1080p</td><td>1920 x 1080</td></tr><tr><td>2K</td><td>2560 x 1440</td></tr><tr><td>4K</td><td>3840 x 2160</td></tr></tbody></table><p>分辨率翻倍不是成本翻倍。1080p 到 4K:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1920 x 1080 = 207 万像素</span></span>
<span class="line"><span>3840 x 2160 = 829 万像素</span></span></code></pre></div><p>像素数是 4 倍,编码、解码、带宽、显存压力都会上去。</p><hr><h2 id="二、帧率-每秒多少张图" tabindex="-1">二、帧率:每秒多少张图 <a class="header-anchor" href="#二、帧率-每秒多少张图" aria-label="Permalink to &quot;二、帧率:每秒多少张图&quot;">​</a></h2><table tabindex="0"><thead><tr><th>帧率</th><th>场景</th></tr></thead><tbody><tr><td>24fps</td><td>电影感</td></tr><tr><td>30fps</td><td>普通视频 / 会议</td></tr><tr><td>60fps</td><td>游戏 / 体育 / 高运动画面</td></tr></tbody></table><p>帧率越高,运动越顺,但编码器每秒要处理更多帧。会议里 30fps 通常够用,低带宽下 15fps 也能接受。屏幕共享文档时,5-15fps 可能就够。</p><blockquote><p>别无脑 60fps。对视频会议来说,稳定 24/30fps 比不稳定 60fps 好。</p></blockquote><hr><h2 id="三、采样率-音频每秒多少点" tabindex="-1">三、采样率:音频每秒多少点 <a class="header-anchor" href="#三、采样率-音频每秒多少点" aria-label="Permalink to &quot;三、采样率:音频每秒多少点&quot;">​</a></h2><p>常见采样率:</p><table tabindex="0"><thead><tr><th>采样率</th><th>场景</th></tr></thead><tbody><tr><td>8000 Hz</td><td>电话窄带语音</td></tr><tr><td>16000 Hz</td><td>语音识别常见</td></tr><tr><td>44100 Hz</td><td>CD / 音乐</td></tr><tr><td>48000 Hz</td><td>视频 / WebRTC 常见</td></tr></tbody></table><p>采样率不是越高越好。语音通话用 48kHz 是工程统一,不代表人声需要这么多信息。真正影响语音体验的通常是回声消除、降噪、丢包恢复和码率。</p><hr><h2 id="四、码率-压缩后每秒给多少比特" tabindex="-1">四、码率:压缩后每秒给多少比特 <a class="header-anchor" href="#四、码率-压缩后每秒给多少比特" aria-label="Permalink to &quot;四、码率:压缩后每秒给多少比特&quot;">​</a></h2><p>码率是编码器预算:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>码率高 -&gt; 细节多,文件大,带宽贵</span></span>
<span class="line"><span>码率低 -&gt; 文件小,容易糊,块状噪声明显</span></span></code></pre></div><p>粗略经验:</p><table tabindex="0"><thead><tr><th>内容</th><th>常见码率</th></tr></thead><tbody><tr><td>语音 Opus</td><td>16-64 kbps</td></tr><tr><td>720p H.264</td><td>1-3 Mbps</td></tr><tr><td>1080p H.264</td><td>3-6 Mbps</td></tr><tr><td>4K H.265 / AV1</td><td>12-30 Mbps</td></tr></tbody></table><p>这些不是定律。动画、PPT、电影、游戏画面需要的码率差别很大。</p><hr><h2 id="五、cbr、vbr、abr" tabindex="-1">五、CBR、VBR、ABR <a class="header-anchor" href="#五、cbr、vbr、abr" aria-label="Permalink to &quot;五、CBR、VBR、ABR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>含义</th><th>适合</th></tr></thead><tbody><tr><td>CBR</td><td>尽量固定码率</td><td>直播上行、带宽固定场景</td></tr><tr><td>VBR</td><td>复杂画面多给,简单画面少给</td><td>点播文件</td></tr><tr><td>ABR</td><td>目标平均码率</td><td>点播 / 转码常用</td></tr></tbody></table><p>点播优先 VBR / CRF,直播更常用 CBR 或受控 ABR。因为直播怕瞬时码率把上行或 CDN 边缘打爆。</p><hr><h2 id="六、crf-给质量-不是给码率" tabindex="-1">六、CRF:给质量,不是给码率 <a class="header-anchor" href="#六、crf-给质量-不是给码率" aria-label="Permalink to &quot;六、CRF:给质量,不是给码率&quot;">​</a></h2><p>x264 / x265 常用 CRF:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -crf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 23</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -preset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> medium</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>CRF 越小质量越高、文件越大。常用范围:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18  质量高</span></span>
<span class="line"><span>23  默认附近</span></span>
<span class="line"><span>28  更小但更糊</span></span></code></pre></div><p>CRF 适合点播,不适合强约束直播。直播需要明确控制输出码率。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>只看分辨率不看码率</strong>——1080p 低码率一样糊。</li><li><strong>只看平均码率</strong>——峰值码率过高也会卡。</li><li><strong>会议无脑高帧率</strong>——低带宽下先保音频,再保分辨率。</li><li><strong>把 CRF 用在直播上</strong>——输出码率不可控,容易爆上行。</li><li><strong>忽略内容类型</strong>——PPT、电影、游戏、体育的码率模型不同。</li></ol><p>下一篇:<code>04-容器格式:MP4 / FLV / MKV / WebM.md</code>。</p>`,42)])])}const k=a(i,[["render",r]]);export{b as __pageData,k as default};
